export const getCandidateMessagingListCandidateMessagesUrl = (conversationId: ModelsUuid,
    params?: CandidateMessagingListCandidateMessagesParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/messages/conversations/${conversationId}/messages?${stringifiedParams}` : `/api/messages/conversations/${conversationId}/messages`
}

